#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long ll;
//#define int ll
inline ll read()
{
	ll res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline void swap(T&x,T&y){T tmp=x;x=y;y=tmp;}
const int N=1e5+10;

int cdt,dep[N],f[N][18],n,m,Q,ql[N],qr[N],idx[N],fa[N],top[N],mxs[N],siz[N],Dep[N];
struct node{ll l,r,f;int rt;}a[N]; struct Pr{ll l,r;}by[N];int cbt;ll dis[N];
int head[N],des[N<<1],nxt[N<<1],cgt;
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}


struct SEG{int l,r,sz;}t[N*18];int Rt[N],cnt;
inline void update(int x){t[x].sz=t[t[x].l].sz+t[t[x].r].sz;}
inline void add(int cur,int &x,int p,int l=1,int r=n)
{
	t[x=++cnt]=t[cur];if(l==r){++t[x].sz;return;} int mid=(l+r)>>1;
	p<=mid?add(t[cur].l,t[x].l,p,l,mid):add(t[cur].r,t[x].r,p,mid+1,r);update(x);
}
inline int kth(int rl,int rr,int k,int l=1,int r=n)
{
	if(l==r)return l;int mid=(l+r)>>1,lsz=t[t[rr].l].sz-t[t[rl].l].sz;
//	printf("kth %d %d %d :: %d\n",l,r,k,lsz);
	if(k<=lsz)return kth(t[rl].l,t[rr].l,k,l,mid);
	else return kth(t[rl].r,t[rr].r,k-lsz,mid+1,r);
}
inline int rnk(int rl,int rr,int x,int l=1,int r=n)
{
	if(l==r)return 0;int mid=(l+r)>>1;
	if(x<=mid)return rnk(t[rl].l,t[rr].l,x,l,mid);
	else return rnk(t[rl].r,t[rr].r,x,mid+1,r)+t[t[rr].l].sz-t[t[rl].l].sz;
}

inline void dfs0(int u=1,int f=0)
{
	siz[u]=1;int mx=0;dep[u]=dep[fa[u]=f]+1;
	grep(u,i)if(des[i]!=f)
	{
		int v=des[i];dfs0(v,u);siz[u]+=siz[v];
		siz[v]>mx?mx=siz[mxs[u]=v]:0;
	}
}
inline void dfs1(int u=1,int fa=0,int tp=1)
{
	idx[ql[u]=++cdt]=u;top[u]=tp;if(mxs[u])dfs1(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs1(des[i],u,des[i]);qr[u]=cdt;
}
inline int Lca(int u,int v)
{
	while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
	return dep[u] < dep[v] ? u : v ;
}


inline int bnd(ll x){int l=1,r=cbt,m;while(l<=r)by[m=(l+r)>>1].l<=x?l=m+1:r=m-1;return l-1;}
inline int Kth(int u,int k){return kth(Rt[ql[u]-1],Rt[qr[u]],k);}
inline int Rnk(int u,int k){return rnk(Rt[ql[u]-1],Rt[qr[u]],k);}
inline int IDX(ll y){int f=bnd(y);return Kth(a[f].rt,y-a[f].l+1);}
inline int DEP(ll y,int f){return dep[IDX(y)]-dep[f];}
inline ll DIS(ll u){int t=bnd(u);return dis[t]+DEP(u,a[t].rt);}
inline ll LCA(ll u,ll v)
{
	int U=bnd(u),V=bnd(v); if(Dep[U]<Dep[V]) swap(u,v),swap(U,V);
	if(U==V)return a[U].l+Rnk(a[U].rt,Lca(IDX(u),IDX(v)));
	drep(17,0,i)if(Dep[f[U][i]]>Dep[V])U=f[U][i];
	if(f[U][0]==V)return a[V].l+Rnk(a[V].rt,Lca(IDX(a[U].f),IDX(v)));
	if(Dep[U]!=Dep[V])U=f[U][0];
	drep(17,0,i)if(f[U][i]!=f[V][i])U=f[U][i],V=f[V][i];
	return a[f[U][0]].l+Rnk(a[f[U][0]].rt,Lca(IDX(a[U].f),IDX(a[V].f)));
}
int main()
{
//	FIN("data.txt");
//	FOUT("mine.txt");
	n=read();m=read()+1;Q=read();
	rep(2,n,i)ins(read(),read());dfs0();dfs1();
	rep(1,n,i)add(Rt[i-1],Rt[i],idx[i]);
	a[1]={1,n,0,1};ll sz=n;by[++cbt]={1,n};
	
	rep(2,m,i)
	{
		int x=read();ll y=read();f[i][0]=bnd(y);
		a[i]={sz+1,sz+siz[x],y,x};
		by[++cbt]={sz+1,sz+siz[x]};sz+=siz[x];
		rep(1,17,j)f[i][j]=f[f[i][j-1]][j-1];
//		printf("cnm :: %lld %d\n",DIS(y),DEP(2,1));
		dis[i]=DIS(y)+1;Dep[i]=Dep[f[i][0]]+1;
	}
//	rep(1,sz,i)printf("%d ",bnd(i));puts("");
//	puts("[l,r,f,rt] :: ");rep(1,m,i)printf("%d :: (%lld,%lld,%lld,%d)\n",i,a[i].l,a[i].r,a[i].f,a[i].rt);
//	rep(1,sz,i)printf("%d ",IDX(i));puts("");
//	printf("QAQ :: %lld\n",LCA(1,4));
//	rep(1,sz,i)printf("%lld ",DIS(i));puts("");
//	rep(1,m,i)printf("%d ",dis[i]);puts("");
	while(Q--)
	{
		ll u=read(),v=read();
		printf("%lld\n",DIS(u)+DIS(v)-2*DIS(LCA(u,v)));
	}
	
}
